pub type SaleDatum {
  seller: VerificationKeyHash,
  min_price: Int,
}

pub type SaleRedeemer {
  Buy
  Cancel
}

validator direct_sale {
  fn spend(datum: Option<SaleDatum>, redeemer: SaleRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Cancel -> list.has(self.extra_signatories, d.seller)
          Buy ->
            list.any(
              self.outputs,
              fn(o: Output) {
                o.address.payment_credential == address.VerificationKey(d.seller) &&
                assets.lovelace_of(o.value) >= d.min_price
              },
            )
        }
    }
  }
}

