pub type EscrowDatum {
  buyer: VerificationKeyHash,
  seller: VerificationKeyHash,
  amount: Int,
}

pub type EscrowRedeemer {
  Release
  Dispute
}

validator escrow_dual_sig {
  fn spend(datum: Option<EscrowDatum>, redeemer: EscrowRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Dispute ->
            list.has(self.extra_signatories, d.buyer) &&
            list.has(self.extra_signatories, d.seller)
          Release -> {
            let both_signed =
              list.has(self.extra_signatories, d.buyer) &&
              list.has(self.extra_signatories, d.seller)
            let seller_receives =
              list.any(
                self.outputs,
                fn(o: Output) {
                  o.address.payment_credential == address.VerificationKey(d.seller) &&
                  assets.lovelace_of(o.value) >= d.amount
                },
              )
            both_signed && seller_receives
          }
        }
    }
  }
}

