                  o.address.payment_credential == address.VerificationKey(d.beneficiary) &&
                  assets.lovelace_of(o.value) >= d.locked_amount
                },
              )
            after_unlock && beneficiary_receives
          }
        }
    }
  }
}

use cardano/assets
use cardano/transaction.{OutputReference, Transaction, Output}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/address

pub type NftMarketDatum {
  seller: VerificationKeyHash,
  marketplace: VerificationKeyHash,
  list_price: Int,
}

pub type NftMarketRedeemer {
  Buy
  Delist
}

validator nft_marketplace {
  fn spend(datum: Option<NftMarketDatum>, redeemer: NftMarketRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let min_price = 5_000_000
        expect d.list_price >= min_price
        when redeemer is {
          Delist -> list.has(self.extra_signatories, d.seller)
          Buy -> {
            let market_fee = d.list_price * 25 / 1000
            let seller_share = d.list_price - market_fee
            let seller_ok =
              list.any(
                self.outputs,
                fn(o: Output) {
                  o.address.payment_credential == address.VerificationKey(d.seller) &&
                  assets.lovelace_of(o.value) >= seller_share
                },
              )
            let market_ok =
              list.any(
                self.outputs,
                fn(o: Output) {
                  o.address.payment_credential == address.VerificationKey(d.marketplace) &&
                  assets.lovelace_of(o.value) >= market_fee
                },
              )
            seller_ok && market_ok
          }
