              recipient == d.buyer || recipient == d.seller
            let recipient_paid =
              list.any(
                self.outputs,
                fn(o: Output) {
                  o.address.payment_credential == address.VerificationKey(recipient) &&
                  assets.lovelace_of(o.value) >= d.amount
