use cardano/assets
use cardano/transaction.{OutputReference, Transaction, Output}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/address

pub type TieredFeeDatum {
  seller: VerificationKeyHash,
  platform: VerificationKeyHash,
  sale_price: Int,
}

pub type TieredFeeRedeemer {
  Buy
  Cancel
}

validator tiered_commission {
  fn spend(datum: Option<TieredFeeDatum>, redeemer: TieredFeeRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Cancel -> list.has(self.extra_signatories, d.seller)
          Buy -> {
            let threshold_high = 100_000_000
            let threshold_mid = 50_000_000
            let fee_rate =
              if d.sale_price > threshold_high {
                3
              } else if d.sale_price > threshold_mid {
                5
              } else {
                7
              }
            let platform_fee = d.sale_price * fee_rate / 100
            let seller_amount = d.sale_price - platform_fee
            let seller_ok =
              list.any(
                self.outputs,
                fn(o: Output) {
                  o.address.payment_credential == address.VerificationKey(d.seller) &&
                  assets.lovelace_of(o.value) >= seller_amount
                },
              )
            let platform_ok =
              list.any(
                self.outputs,
                fn(o: Output) {
                  o.address.payment_credential == address.VerificationKey(d.platform) &&
                  assets.lovelace_of(o.value) >= platform_fee
                },
              )
            seller_ok && platform_ok
          }
        }
    }
  }
}

