use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/interval
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type CrowdfundDatum {
  proyecto: VerificationKeyHash,
  donante: VerificationKeyHash,
  fecha_limite: Int,
  objetivo: Int,
}

pub type CrowdfundRedeemer {
  LibrarFondos
  Reembolsar
}

validator crowdfunding_tiempo {
  fn spend(
    datum: Option<CrowdfundDatum>,
    redeemer: CrowdfundRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          LibrarFondos -> {
            let antes_limite =
              interval.is_entirely_before(
                self.validity_range,
                d.fecha_limite,
              )
            let objetivo_alcanzado =
              list.any(
                self.outputs,
                fn(o) { assets.lovelace_of(o.value) >= d.objetivo },
              )
            list.has(self.extra_signatories, d.proyecto) && antes_limite && objetivo_alcanzado
          }
          Reembolsar ->
            list.has(self.extra_signatories, d.donante) && interval.is_entirely_after(
              self.validity_range,
              d.fecha_limite,
            )
        }
    }
  }
}

