    when redeemer is {
      NormalMint -> {
        let before = interval.is_entirely_before(self.validity_range, deadline)
        let qty = assets.quantity_of(self.mint, policy_id, "EXPIRING")
        list.has(self.extra_signatories, admin) && before && qty > 0
