pub type OracleDatum {
  price: Int,
}

pub type PriceRedeemer {
  oracle_ref: OutputReference,
  claimed_price: Int,
}

validator oracle_price_check {
  fn spend(
    _datum: Option<Void>,
    redeemer: PriceRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(oracle_input) =
      transaction.find_input(self.reference_inputs, redeemer.oracle_ref)
    expect InlineDatum(raw) = oracle_input.output.datum
    expect oracle_datum: OracleDatum = raw
    let oracle_price = oracle_datum.price
    let diff =
      if redeemer.claimed_price >= oracle_price {
        redeemer.claimed_price - oracle_price
      } else {
        oracle_price - redeemer.claimed_price
      }
    diff * 100 <= oracle_price * 5
  }
}

