    expect Some(stake_datum) = datum
    expect Some(cfg_input) =
      transaction.find_input(self.reference_inputs, redeemer.config_ref)
    expect InlineDatum(raw) = cfg_input.output.datum
    expect cfg: StakingConfig = raw
    let elapsed = redeemer.claim_time - stake_datum.deposit_time
    let epochs = elapsed / cfg.epoch_length
    let reward = stake_datum.deposited * cfg.reward_rate_bps * epochs / 10000
    let total_due = stake_datum.deposited + reward
    list.any(
      self.outputs,
      fn(o) {
        o.address.payment_credential == redeemer.recipient
          && assets.lovelace_of(o.value) >= total_due
      },
    )
  }
}

use aiken/collection/list
use cardano/assets.{PolicyId}
use cardano/transaction.{InlineDatum, OutputReference, Transaction}

pub type PoolParams {
  pool_policy: PolicyId,
  pool_name: ByteArray,
  fee_bps: Int,
}

pub type LiquidityDatum {
  reserve_a: Int,
  reserve_b: Int,
}

pub type SwapLiqRedeemer {
  params_ref: OutputReference,
  delta_a: Int,
  delta_b: Int,
  pool_script_hash: ByteArray,
}

validator liquidity_pool_spend {
  fn spend(
    datum: Option<LiquidityDatum>,
    redeemer: SwapLiqRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(pool_datum) = datum
    expect Some(params_input) =
      transaction.find_input(self.reference_inputs, redeemer.params_ref)
    expect InlineDatum(raw) = params_input.output.datum
    expect _params: PoolParams = raw
    let k = pool_datum.reserve_a * pool_datum.reserve_b
    let new_reserve_a = pool_datum.reserve_a + redeemer.delta_a
    let new_reserve_b = pool_datum.reserve_b + redeemer.delta_b
    let new_k = new_reserve_a * new_reserve_b
    let pool_output_ok =
      list.any(
        self.outputs,
        fn(o) { o.address.payment_credential == redeemer.pool_script_hash },
      )
    new_k >= k && pool_output_ok
  }
}

