  AdditionalMint {
    name: ByteArray,
    quantity: Int,
    signers: List<VerificationKeyHash>,
    threshold: Int,
  }
  PartialBurn { name: ByteArray, amount: Int, signer: VerificationKeyHash }
  NameSwap {
    old_name: ByteArray,
    new_name: ByteArray,
    signer: VerificationKeyHash,
  }
}

validator quad_action_mint {
  fn mint(
    redeemer: QuadActionRedeemer,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    when redeemer is {
      InitialMint { seed, name, supply } -> {
        let consumed =
          list.any(
            self.inputs,
            fn(i) { i.output_reference == seed },
          )
        let minted = assets.quantity_of(self.mint, policy_id, name)
        consumed && minted == supply && supply > 0
      }
      AdditionalMint { name, quantity, signers, threshold } -> {
        let sig_count =
          list.count(signers, fn(k) { list.has(self.extra_signatories, k) })
        let minted = assets.quantity_of(self.mint, policy_id, name)
        minted == quantity && quantity > 0 && sig_count >= threshold
      }
      PartialBurn { name, amount, signer } -> {
        let burned = assets.quantity_of(self.mint, policy_id, name)
        burned == -amount && amount > 0 && list.has(
          self.extra_signatories,
          signer,
        )
      }
      NameSwap { old_name, new_name, signer } -> {
        let burned = assets.quantity_of(self.mint, policy_id, old_name)
        let minted = assets.quantity_of(self.mint, policy_id, new_name)
        burned == -1 && minted == 1 && list.has(
          self.extra_signatories,
          signer,
        )
      }
    }
  }
}

