          list.any(
            self.outputs,
            fn(o) { assets.lovelace_of(o.value) >= d.precio },
          )
        mercado_abierto && firmado && pago_correcto
      }
    }
  }
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/interval
use cardano/assets
