  Withdraw
}

validator dao_vote_window {
  fn spend(
    datum: Option<DaoDatum>,
    redeemer: DaoRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          CastVote -> {
            let vote_window = interval.between(d.vote_start, d.vote_end)
            let in_voting = interval.includes(vote_window, self.validity_range)
            let signed = list.has(self.extra_signatories, d.voter)
            in_voting && signed
          }
          Withdraw -> {
            let after_vote =
              interval.is_entirely_after(self.validity_range, d.vote_end)
            let signed = list.has(self.extra_signatories, d.voter)
            after_vote && signed
          }
        }
    }
  }
}

