        when dict.get(d.rates, redeemer.currency) is {
          None -> False
          Some(rate) -> {
            let expected_lovelace = redeemer.token_amount * rate
            let recipient_addr = address.from_verification_key(d.recipient)
            list.any(
              self.outputs,
              fn(o) {
                o.address == recipient_addr && assets.lovelace_of(o.value) >= expected_lovelace
              },
            )
          }
        }
    }
  }
}

