validator dao {
  fn spend(
    datum: Option<DaoDatum>,
    redeemer: DaoRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          WithdrawTreasury ->
            list.count(
              d.admins,
              fn(k) { list.has(self.extra_signatories, k) },
            ) >= d.quorum
          UpdateParams ->
            list.count(
              d.admins,
              fn(k) { list.has(self.extra_signatories, k) },
            ) >= d.quorum
        }
    }
  }

  fn mint(
    redeemer: ByteArray,
    policy_id: PolicyId,
