use aiken/collection/list
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

pub type BridgeDatum {
  relayer: ByteArray,
  source_tx_hash: ByteArray,
  amount: Int,
  recipient: ByteArray,
}

pub type BridgeRedeemer {
  Unlock { proof: ByteArray }
  Cancel
}

validator cross_chain_bridge {
  fn spend(
    datum: Option<BridgeDatum>,
    redeemer: BridgeRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Unlock { proof } ->
            proof == d.source_tx_hash && list.has(
              self.extra_signatories,
              d.relayer,
            ) && list.any(
              self.outputs,
              fn(o) { assets.lovelace_of(o.value) >= d.amount },
            )
          Cancel ->
            list.has(self.extra_signatories, d.relayer)
        }
    }
  }

  fn mint(
    redeemer: Int,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let qty = assets.quantity_of(self.mint, policy_id, "WRAP")
    qty == redeemer && (redeemer > 0 || redeemer < 0)
  }
}

use aiken/collection/list
use aiken/interval
use cardano/address.{Credential}
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

pub type BidDatum {
  auctioneer: ByteArray,
  bidder: ByteArray,
  bid_amount: Int,
  reveal_deadline: Int,
  nft_policy: ByteArray,
  nft_name: ByteArray,
}

pub type BidRedeemer {
  Reveal
  Forfeit
}

validator sealed_bid_auction {
  fn spend(
    datum: Option<BidDatum>,
    redeemer: BidRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Reveal ->
            list.has(self.extra_signatories, d.bidder) && interval.is_entirely_before(
              self.validity_range,
              d.reveal_deadline,
            ) && list.any(
              self.outputs,
              fn(o) { assets.lovelace_of(o.value) >= d.bid_amount },
            )
          Forfeit ->
            interval.is_entirely_after(
              self.validity_range,
              d.reveal_deadline,
            ) && list.has(self.extra_signatories, d.auctioneer)
        }
    }
  }

  fn mint(
    redeemer: ByteArray,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let qty = assets.quantity_of(self.mint, policy_id, redeemer)
    qty == 1 || qty == -1
  }

  fn withdraw(
    redeemer: ByteArray,
    _account: Credential,
    self: Transaction,
  ) -> Bool {
    list.has(self.extra_signatories, redeemer)
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type RoyaltyDatum {
  creator: ByteArray,
  platform: ByteArray,
  sale_price: Int,
  royalty_bps: Int,
}

pub type RoyaltyRedeemer {
  Sale
  DirectTransfer
}

validator royalties_contract {
  fn spend(
    datum: Option<RoyaltyDatum>,
    redeemer: RoyaltyRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Sale ->
            let royalty_amount = d.sale_price * d.royalty_bps / 10000
            list.any(
              self.outputs,
              fn(o) { assets.lovelace_of(o.value) >= royalty_amount },
            ) && list.any(
              self.outputs,
              fn(o) {
                assets.lovelace_of(o.value) >= d.sale_price - royalty_amount
              },
            )
          DirectTransfer ->
            list.has(self.extra_signatories, d.creator)
        }
    }
  }

  fn withdraw(
    redeemer: ByteArray,
    _account: Credential,
    self: Transaction,
  ) -> Bool {
    list.has(self.extra_signatories, redeemer)
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

pub type CurveDatum {
  owner: ByteArray,
  supply: Int,
  reserve: Int,
  slope: Int,
}

pub type CurveRedeemer {
  Buy { amount: Int }
  Sell { amount: Int }
}

validator bonding_curve {
  fn spend(
    datum: Option<CurveDatum>,
    redeemer: CurveRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Buy { amount } ->
            amount > 0 && list.any(
              self.outputs,
              fn(o) {
                assets.lovelace_of(o.value) >= amount * d.slope * d.supply / 1000
              },
            )
          Sell { amount } ->
            amount > 0 && amount <= d.supply && list.has(
              self.extra_signatories,
              d.owner,
            )
        }
    }
  }

  fn mint(
    redeemer: Int,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let qty = assets.quantity_of(self.mint, policy_id, "CURVE")
    qty == redeemer && redeemer != 0
  }

  fn withdraw(
    redeemer: ByteArray,
    _account: Credential,
    self: Transaction,
  ) -> Bool {
    list.has(self.extra_signatories, redeemer)
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

pub type FractionDatum {
  owner: ByteArray,
  nft_policy: ByteArray,
  nft_name: ByteArray,
  total_fractions: Int,
  buyout_price: Int,
}

pub type FractionRedeemer {
  Transfer { amount: Int }
  Buyout
  Redeem
}

validator nft_fractionalization {
  fn spend(
    datum: Option<FractionDatum>,
    redeemer: FractionRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Transfer { amount } ->
            amount > 0 && amount <= d.total_fractions
          Buyout ->
            list.any(
              self.outputs,
              fn(o) { assets.lovelace_of(o.value) >= d.buyout_price },
            )
          Redeem ->
            list.has(self.extra_signatories, d.owner) && assets.has_nft(
              self.mint,
              d.nft_policy,
              d.nft_name,
            )
        }
    }
  }

  fn mint(
    redeemer: Int,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let qty = assets.quantity_of(self.mint, policy_id, "FRAC")
    qty == redeemer && redeemer != 0
  }

  fn withdraw(
    redeemer: ByteArray,
    _account: Credential,
    self: Transaction,
  ) -> Bool {
    list.has(self.extra_signatories, redeemer) && list.any(
      self.outputs,
      fn(o) { assets.lovelace_of(o.value) > 0 },
    )
  }
}
